  howItWorksTitle: { EN: "Connect. Travel. Repeat.", ES: "Conecta. Viaja. Repite.", FR: "Connectez. Voyagez. Répétez.", DE: "Verbinden. Reisen. Wiederholen.", RU: "Подключиться. Путешествовать. Повторить.", ZH: "连接。旅行。重复。", JA: "接続。旅行。繰り返し。", PT: "Conecte. Viaje. Repita.", AR: "اتصل. سافر. كرر.", HI: "कनेक्ट करें। यात्रा करें। दोहराएं।" },
  howItWorksSubtitle: { EN: "Your eSIM journey begins in seconds. No queues, no paperwork, no compromises.", ES: "Tu viaje eSIM comienza en segundos. Sin colas, sin papeleo, sin compromisos.", FR: "Votre parcours eSIM commence en quelques secondes. Pas de files d'attente, pas de paperasse, pas de compromis.", DE: "Deine eSIM-Reise beginnt in Sekunden. Keine Warteschlangen, kein Papierkram, keine Kompromisse.", RU: "Ваше путешествие с eSIM начинается за секунды. Никаких очередей, никакой бумажной волокиты, никаких компромиссов.", ZH: "您的 eSIM 之旅在几秒钟内开始。无需排队，无需文书工作，无需妥协。", JA: "あなたのeSIMの旅は数秒で始まります。待ち行列なし、書類なし、妥協なし。", PT: "Sua jornada eSIM começa em segundos. Sem filas, sem papelada, sem compromissos.", AR: "تبدأ رحلتك مع eSIM في ثوانٍ. بدون طوابير، بدون أوراق، بدون تنازلات.", HI: "आपकी eSIM यात्रा सेकंडों में शुरू होती है। कोई लाइन नहीं, कोई कागजी काम नहीं, कोई समझौता नहीं।" },
  howItWorksStep1: { EN: "Select plan", ES: "Selecciona plan", FR: "Sélectionner le plan", DE: "Plan auswählen", RU: "Выберите план", ZH: "选择计划", JA: "プランを選択", PT: "Selecionar plano", AR: "اختر الخطة", HI: "प्लान चुनें" },
