function isRTL(lang: Language) {
  return lang === "AR"; // Arabic
}

function detectBrowserLanguage(): Language {
  if (typeof navigator === 'undefined') return "EN";
  
  const browserLang = navigator.language || (navigator as any).userLanguage;
  const langCode = browserLang.split('-')[0].toUpperCase();
  
  const langMap: Record<string, Language> = {
    'EN': 'EN', 'ES': 'ES', 'FR': 'FR', 'DE': 'DE', 
    'RU': 'RU', 'ZH': 'ZH', 'JA': 'JA', 'PT': 'PT', 
    'AR': 'AR', 'IT': 'IT'
  };
  
  return langMap[langCode] || "EN";
}

// getInitialLanguage moved below to support path-based locale slugs

export function TranslationProvider({ children }: { children: ReactNode }) {
  const [language, setLang] = useState<Language>(getInitialLanguage);

  useEffect(() => {
    // Persist to localStorage
    if (typeof window !== 'undefined') {
      localStorage.setItem("lang", language);
    }
    
    // Update document attributes
    const dir = isRTL(language) ? "rtl" : "ltr";
    if (typeof document !== 'undefined' && document.documentElement) {
      document.documentElement.setAttribute("dir", dir);
      document.documentElement.setAttribute("lang", language.toLowerCase());
    }
  }, [language]);

  const t = useMemo(() => {
    return (key: string) => {
      const entry = translations[key];
      if (!entry) return key;
      return entry[language] ?? entry["EN"] ?? key;
    };
  }, [language]);

  const value = useMemo<TranslationContextType>(() => ({
    language,
    setLanguage: (l: Language) => setLang(l),
    t,
  }), [language, t]);

  return (
    <TranslationContext.Provider value={value}>
      {children}
    </TranslationContext.Provider>
  );
}

function getPathLanguage(): Language | null {
  if (typeof window === 'undefined') return null;
  const slug = window.location.pathname.split('/')[1]?.toLowerCase();
  const slugMap: Record<string, Language> = {
    english: 'EN', espanol: 'ES', francais: 'FR', deutsch: 'DE',
    russian: 'RU', chinese: 'ZH', japanese: 'JA', portugues: 'PT', arabic: 'AR', italiano: 'IT'
  };
  return slug ? slugMap[slug] ?? null : null;
}

function getInitialLanguage(): Language {
  if (typeof window === 'undefined') return "EN";

  // 1) From path slug
  const fromPath = getPathLanguage();
  if (fromPath) return fromPath;

  // 2) From localStorage
  const savedLang = localStorage.getItem("lang") as Language | null;
  if (savedLang && ['EN','ES','FR','DE','RU','ZH','JA','PT','AR','IT'].includes(savedLang)) {
    return savedLang;
  }

  // 3) From browser
  return detectBrowserLanguage();
}

export function useTranslation() {
  const ctx = useContext(TranslationContext);
  if (!ctx) {
    throw new Error("useTranslation must be used within TranslationProvider");
  }
  return ctx;
}
